9	    priority: row.priority,
10	    status: row.status,
11	    attempts: row.attempts,
12	    maxAttempts: row.max_attempts,
13	    nextRetryAt: row.next_retry_at ? new Date(row.next_retry_at) : null,
14	    lastError: row.last_error,
15	    shardKey: row.shard_key,
16	    idempotencyKey: row.idempotency_key,
17	    lockedBy: row.locked_by,
18	    orgId: row.org_id ?? null,
19	    createdAt: new Date(row.created_at),
20	    startedAt: row.started_at ? new Date(row.started_at) : null,
21	    completedAt: row.completed_at ? new Date(row.completed_at) : null,
22	  };
23	}
24	
25	const TOTAL_SHARDS = 4;
26	
27	function computeShardKey(input: string): number {
28	  let hash = 0;
29	  for (let i = 0; i < input.length; i++) {
30	    hash = ((hash << 5) - hash + input.charCodeAt(i)) | 0;
31	  }
32	  return Math.abs(hash) % TOTAL_SHARDS;
33	}
