32	export default async function webhookRoutes(app: FastifyInstance) {
33	  // GET /api/webhooks — returns masked secrets
34	  app.get('/api/webhooks', {
35	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
36	  }, async (request: FastifyRequest) => {
37	    const db = request.db;
38	    const rows = await db('webhook_configs').where({ org_id: request.user.orgId });
39	    return { data: rows.map(sanitizeWebhook) };
40	  });
41	
42	  // POST /api/webhooks
43	  app.post('/api/webhooks', {
44	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
45	  }, async (request: FastifyRequest, reply: FastifyReply) => {
46	    const parsed = createWebhookSchema.safeParse(request.body);
47	    if (!parsed.success) {
48	      return reply.status(422).send({ error: 'VALIDATION_ERROR', message: 'Invalid input', details: parsed.error.issues });
49	    }
50	
51	    const db = request.db;
52	
53	    const [webhook] = await db('webhook_configs').insert({
54	      org_id: request.user.orgId,
55	      url: parsed.data.url,
56	      events: JSON.stringify(parsed.data.events),
57	      secret: encrypt(parsed.data.secret),
58	    }).returning('*');
59	
60	    return reply.status(201).send({ webhook: sanitizeWebhook(webhook) });
61	  });
62	
63	  // PATCH /api/webhooks/:id
64	  app.patch('/api/webhooks/:id', {
65	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
66	  }, async (request: FastifyRequest, reply: FastifyReply) => {
67	    const { id } = request.params as { id: string };
68	    const body = request.body as Record<string, any>;
69	    const db = request.db;
70	
71	    const [webhook] = await db('webhook_configs')
72	      .where({ id, org_id: request.user.orgId })
73	      .update({
74	        url: body.url,
75	        events: body.events ? JSON.stringify(body.events) : undefined,
76	        is_active: body.isActive,
77	      })
78	      .returning('*');
79	
80	    if (!webhook) {
81	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Webhook not found' });
82	    }
83	    return { webhook: sanitizeWebhook(webhook) };
84	  });
85	
86	  // POST /api/webhooks/:id/rotate-secret — replace secret without exposing current value
87	  app.post('/api/webhooks/:id/rotate-secret', {
88	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
89	  }, async (request: FastifyRequest, reply: FastifyReply) => {
90	    const { id } = request.params as { id: string };
91	    const parsed = rotateSecretSchema.safeParse(request.body);
92	    if (!parsed.success) {
93	      return reply.status(422).send({ error: 'VALIDATION_ERROR', message: 'Invalid input', details: parsed.error.issues });
94	    }
95	
96	    const db = request.db;
97	
98	    const [webhook] = await db('webhook_configs')
99	      .where({ id, org_id: request.user.orgId })
100	      .update({ secret: encrypt(parsed.data.secret) })
101	      .returning('*');
102	
103	    if (!webhook) {
104	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Webhook not found' });
105	    }
106	    return { webhook: sanitizeWebhook(webhook), message: 'Secret rotated successfully' };
107	  });
108	}
