10	export default async function reportRoutes(app: FastifyInstance) {
11	  // GET /api/reports/dashboard
12	  app.get('/api/reports/dashboard', {
13	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
14	  }, async (request: FastifyRequest) => {
15	    const db = request.db;
16	
17	    const query = request.query as Record<string, string>;
18	    const { orgId, role } = request.user;
19	
20	    // For super_admin: no orgId param means aggregate across all orgs
21	    const targetOrgId = role === 'super_admin'
22	      ? (query.orgId || null)
23	      : orgId;
24	    const from = query.from ? new Date(query.from) : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
25	    const to = query.to ? new Date(query.to) : new Date();
26	
27	    let bookingQuery = db('bookings')
28	      .where('created_at', '>=', from)
29	      .where('created_at', '<=', to);
30	    if (targetOrgId) bookingQuery = bookingQuery.where('org_id', targetOrgId);
31	
32	    if (query.role) {
33	      let userFilter = db('users').select('id').where({ role: query.role });
34	      if (targetOrgId) userFilter = userFilter.where({ org_id: targetOrgId });
35	      if (query.role === 'client') {
36	        bookingQuery = bookingQuery.whereIn('client_id', userFilter);
37	      } else if (query.role === 'lawyer') {
38	        bookingQuery = bookingQuery.whereIn('lawyer_id', userFilter);
39	      }
40	    }
41	
42	    const totalBookings = await bookingQuery.clone().count('id as count').first();
43	    const completedBookings = await bookingQuery.clone().where({ status: 'completed' }).count('id as count').first();
44	    const noShows = await bookingQuery.clone().where({ status: 'no_show' }).count('id as count').first();
45	    const cancellations = await bookingQuery.clone().where({ status: 'cancelled' }).count('id as count').first();
46	
47	    const totalCount = Number(totalBookings?.count ?? 0);
48	    const completedCount = Number(completedBookings?.count ?? 0);
49	    const noShowCount = Number(noShows?.count ?? 0);
50	    const cancellationCount = Number(cancellations?.count ?? 0);
51	
52	    // Availability: count of active availability slots vs booked
53	    let slotsQuery = db('availability').where({ is_active: true });
54	    if (targetOrgId) {
55	      slotsQuery = slotsQuery.whereIn('lawyer_id', db('users').select('id').where({ org_id: targetOrgId, role: 'lawyer' }));
56	    }
57	    const totalSlots = await slotsQuery.count('id as count').first();
58	    const totalSlotsCount = Number(totalSlots?.count ?? 1);
59	
60	    // Alerts / incidents (disputes)
61	    let disputeUserFilter = db('users').select('id');
62	    if (targetOrgId) disputeUserFilter = disputeUserFilter.where({ org_id: targetOrgId });
63	
64	    const totalDisputes = await db('disputes')
65	      .whereIn('appellant_id', disputeUserFilter)
66	      .where('filed_at', '>=', from).where('filed_at', '<=', to)
67	      .count('id as count').first();
68	    const resolvedDisputes = await db('disputes')
69	      .whereIn('appellant_id', disputeUserFilter)
70	      .where('filed_at', '>=', from).where('filed_at', '<=', to)
71	      .whereIn('status', ['resolved', 'dismissed'])
72	      .count('id as count').first();
73	
74	    const disputeTotal = Number(totalDisputes?.count ?? 0);
75	    const disputeResolved = Number(resolvedDisputes?.count ?? 0);
76	
77	    return {
78	      availability: totalSlotsCount > 0 ? Math.round(((totalSlotsCount - completedCount) / totalSlotsCount) * 100) : 0,
79	      faultRate: totalCount > 0 ? Math.round(((noShowCount + cancellationCount) / totalCount) * 100) : 0,
80	      utilization: totalSlotsCount > 0 ? Math.round((completedCount / totalSlotsCount) * 100) : 0,
81	      throughput: completedCount,
82	      closedLoopEfficiency: disputeTotal > 0 ? Math.round((disputeResolved / disputeTotal) * 100) : 100,
83	      period: { from: from.toISOString(), to: to.toISOString() },
84	    };
85	  });
86	
87	  // GET /api/reports/export
88	  app.get('/api/reports/export', {
89	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
90	  }, async (request: FastifyRequest, reply: FastifyReply) => {
91	    const query = request.query as Record<string, string>;
92	    const format = query.format ?? 'csv';
93	    const db = request.db;
