110	    const bookings = await exportQuery
111	      .orderBy('created_at', 'desc')
112	      .limit(1000);
113	
114	    if (format === 'csv') {
115	      const { Parser } = await import('json2csv');
116	      const fields = ['id', 'client_id', 'lawyer_id', 'type', 'status', 'scheduled_at', 'created_at'];
117	      const parser = new Parser({ fields });
