137	
138	      const buffer = await workbook.xlsx.writeBuffer();
139	      reply.header('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
140	      reply.header('Content-Disposition', 'attachment; filename="report.xlsx"');
141	      return reply.send(Buffer.from(buffer as ArrayBuffer));
142	    }
143	  });
144	
