52	  await app.register(reportRoutes);
53	  await app.register(adminRoutes);
54	  await app.register(webhookRoutes);
55	  await app.register(configRoutes);
56	
57	  // Global error handler
58	  app.setErrorHandler((error: any, request, reply) => {
59	    const statusCode = error.statusCode ?? 500;
60	
61	    if (statusCode >= 500) {
62	      logger.error({
63	        err: error.message,
64	        stack: error.stack,
65	        method: request.method,
66	        url: request.url,
67	        userId: (request as any).userId,
68	      }, 'Internal server error');
69	    }
70	
71	    const response: Record<string, unknown> = {
72	      error: getErrorCode(statusCode),
73	      message: statusCode >= 500 ? 'An unexpected error occurred' : error.message,
74	    };
75	
76	    if (error.details) {
77	      response.details = error.details;
78	    }
79	
80	    if (error.retryAfterSeconds) {
81	      response.retryAfterSeconds = error.retryAfterSeconds;
82	    }
83	
84	    reply.status(statusCode).send(response);
85	  });
86	
87	  // Health check
88	  app.get('/api/health', async () => {
89	    return { status: 'ok', timestamp: new Date().toISOString() };
90	  });
91	
92	  // Time sync endpoint (public)
