100	function getErrorCode(statusCode: number): string {
101	  const codes: Record<number, string> = {
102	    400: 'BAD_REQUEST',
103	    401: 'UNAUTHORIZED',
104	    403: 'FORBIDDEN',
105	    404: 'NOT_FOUND',
106	    409: 'CONFLICT',
107	    422: 'VALIDATION_ERROR',
108	    423: 'LOCKED',
109	    429: 'RATE_LIMITED',
110	    500: 'INTERNAL_ERROR',
111	    503: 'SERVICE_UNAVAILABLE',
112	  };
113	  return codes[statusCode] ?? 'UNKNOWN_ERROR';
114	}
