1	import fp from 'fastify-plugin';
2	import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
3	import { Knex } from 'knex';
4	
5	async function consumeToken(db: Knex, bucketId: string, maxTokens: number, refillRate: number): Promise<{ allowed: boolean; retryAfterSeconds: number }> {
6	  const now = new Date();
7	
8	  // Upsert bucket
9	  await db.raw(`
10	    INSERT INTO rate_limit_buckets (id, tokens, max_tokens, refill_rate, last_refill_at)
11	    VALUES (?, ?, ?, ?, ?)
12	    ON CONFLICT (id) DO NOTHING
13	  `, [bucketId, maxTokens, maxTokens, refillRate, now]);
14	
15	  // Atomic refill + consume
16	  const result = await db.raw(`
17	    UPDATE rate_limit_buckets
18	    SET
19	      tokens = LEAST(
20	        max_tokens,
21	        tokens + refill_rate * EXTRACT(EPOCH FROM (NOW() - last_refill_at))
22	      ) - 1,
23	      last_refill_at = NOW()
24	    WHERE id = ?
25	    RETURNING tokens
26	  `, [bucketId]);
27	
28	  const remaining = result.rows[0]?.tokens ?? 0;
29	  if (remaining < 0) {
30	    const retryAfter = Math.ceil(1 / refillRate);
31	    return { allowed: false, retryAfterSeconds: retryAfter };
32	  }
33	  return { allowed: true, retryAfterSeconds: 0 };
34	}
35	
36	export async function rateLimitBooking(request: FastifyRequest, reply: FastifyReply) {
37	  if (!request.user) return;
38	
39	  const { userId, orgId } = request.user;
40	  const db = request.db;
41	
42	  // Per-user limit: 20/min = 0.333/sec
43	  const userResult = await consumeToken(db, `user:${userId}`, 20, 20 / 60);
44	  if (!userResult.allowed) {
45	    return reply.status(429).send({
46	      error: 'RATE_LIMITED',
47	      message: 'Too many requests. Please try again later.',
48	      retryAfterSeconds: userResult.retryAfterSeconds,
49	    });
50	  }
51	
52	  // Per-org limit: 200/min = 3.333/sec
53	  const orgResult = await consumeToken(db, `org:${orgId}`, 200, 200 / 60);
54	  if (!orgResult.allowed) {
55	    return reply.status(429).send({
56	      error: 'RATE_LIMITED',
57	      message: 'Organization rate limit exceeded. Please try again later.',
58	      retryAfterSeconds: orgResult.retryAfterSeconds,
59	    });
60	  }
61	}
62	
63	export default fp(async (_app: FastifyInstance) => {
64	  // Plugin registers the rateLimitBooking preHandler utility
65	}, { name: 'rate-limit' });
