199	  app.patch('/api/disputes/:id/resolve', {
200	    preHandler: [app.authenticate, authorize('admin', 'super_admin')],
201	  }, async (request: FastifyRequest, reply: FastifyReply) => {
202	    const { id } = request.params as { id: string };
203	    const parsed = resolveDisputeSchema.safeParse(request.body);
204	    if (!parsed.success) {
205	      return reply.status(422).send({ error: 'VALIDATION_ERROR', message: 'Invalid input', details: parsed.error.issues });
206	    }
207	
208	    const db = request.db;
209	
210	    const reviewRepo = new KnexReviewRepository(db);
211	    const creditRepo = new KnexCreditRepository(db);
212	    const userRepo = new KnexUserRepository(db);
213	
214	    const dispute = await reviewRepo.findDisputeById(id);
215	    if (!dispute) {
216	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Dispute not found' });
217	    }
218	
219	    if (dispute.status === 'resolved' || dispute.status === 'dismissed') {
220	      return reply.status(409).send({ error: 'CONFLICT', message: 'Dispute already resolved' });
221	    }
222	
223	    const isUpheld = parsed.data.resolution === 'upheld';
224	    const newStatus = isUpheld ? 'resolved' : 'dismissed';
225	
226	    // If dismissed, re-apply escrowed penalties atomically
227	    if (!isUpheld && dispute.penaltyEscrowed) {
228	      let totalPenalty = 0;
229	      for (const entry of dispute.penaltyEscrowed as any[]) {
230	        totalPenalty += entry.changeAmount;
231	      }
232	      // Atomic credit score update — avoids race with concurrent modifications
233	      await db.raw(`
234	        UPDATE users
235	        SET credit_score = LEAST(100, GREATEST(0, credit_score + ?))
236	        WHERE id = ?
237	      `, [totalPenalty, dispute.appellantId]);
238	    }
239	
240	    await creditRepo.resolveEscrow(id, !isUpheld);
241	
242	    const updated = await reviewRepo.updateDispute(id, {
243	      status: newStatus,
244	      resolutionNotes: parsed.data.notes ?? null,
245	      adminId: request.user.userId,
246	      resolvedAt: new Date(),
247	    });
248	
249	    return { dispute: updated };
250	  });
251	}
