13	export default fp(async (app: FastifyInstance) => {
14	  app.addHook('onRequest', async (request: FastifyRequest) => {
15	    const knex = getKnex();
16	    request.db = await knex.transaction();
17	    request._dbCommitted = false;
18	    await request.db.raw("SET LOCAL app.bypass_rls = 'false'");
19	  });
20	
21	  // Use onResponse to commit — fires AFTER the reply is fully sent,
22	  // avoiding ERR_HTTP_HEADERS_SENT when preHandlers throw errors.
23	  // The tradeoff is a small window where committed data from this request
24	  // may not be visible to the next request from the same client.
25	  // For login, we handle this by having the frontend retry on 401.
26	  app.addHook('onResponse', async (request: FastifyRequest) => {
27	    if (request.db && !request._dbCommitted) {
28	      try {
29	        await request.db.commit();
30	        request._dbCommitted = true;
31	      } catch {
32	        // Transaction already completed
33	      }
34	    }
35	  });
36	
37	  app.addHook('onError', async (request: FastifyRequest) => {
38	    if (request.db && !request._dbCommitted) {
39	      try {
40	        await request.db.rollback();
41	        request._dbCommitted = true;
42	      } catch {
43	        // Transaction already completed
44	      }
45	    }
46	  });
47	}, { name: 'org-isolation' });
