29	async function deliverWithRetry(url: string, body: string, signature: string): Promise<{ status: number; ok: boolean }> {
30	  let lastError: Error | null = null;
31	
32	  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
33	    if (attempt > 0) {
34	      const backoffMs = RETRY_BACKOFF_BASE_MS * Math.pow(2, attempt - 1);
35	      await new Promise(resolve => setTimeout(resolve, backoffMs));
36	    }
37	
38	    try {
39	      const controller = new AbortController();
40	      const timeout = setTimeout(() => controller.abort(), DELIVERY_TIMEOUT_MS);
41	
42	      const response = await fetch(url, {
43	        method: 'POST',
44	        headers: {
45	          'Content-Type': 'application/json',
46	          'X-Webhook-Signature': signature,
47	          'X-Webhook-Timestamp': new Date().toISOString(),
48	        },
49	        body,
50	        signal: controller.signal,
51	      });
52	
53	      clearTimeout(timeout);
54	
55	      if (response.ok || response.status < 500) {
56	        return { status: response.status, ok: response.ok };
57	      }
58	
59	      lastError = new Error(`HTTP ${response.status}`);
60	    } catch (err: any) {
61	      lastError = err;
62	    }
63	  }
64	
65	  throw lastError ?? new Error('Webhook delivery failed');
66	}
