72	    const configs = await this.db('webhook_configs')
73	      .where({ org_id: orgId, is_active: true });
74	
75	    const matchingWebhooks = configs.filter((cfg: WebhookConfig) => {
76	      const events = typeof cfg.events === 'string' ? JSON.parse(cfg.events) : cfg.events;
77	      return events.includes(event) || events.includes('*');
78	    });
79	
80	    if (matchingWebhooks.length === 0) return;
