82	    const payload: WebhookPayload = {
83	      event,
84	      timestamp: new Date().toISOString(),
85	      data,
86	    };
87	    const body = JSON.stringify(payload);
88	
89	    for (const webhook of matchingWebhooks) {
90	      let secret: string;
91	      try {
92	        secret = decrypt(webhook.secret);
93	      } catch {
