 * Validate webhook URL safety.
 *
 * Policy is configurable via WEBHOOK_ALLOW_PRIVATE env var:
 *   - "true"  → allows private/LAN addresses (on-prem / air-gapped deployments)
 *   - "false" or unset → blocks private ranges, cloud metadata, and loopback (default-safe)
 *
 * Cloud metadata endpoints (169.254.169.254, metadata.google.internal) are
 * always blocked regardless of policy — these are never legitimate webhook targets.
 */
const ALLOW_PRIVATE = process.env.WEBHOOK_ALLOW_PRIVATE === 'true';

function isValidWebhookUrl(urlStr: string): boolean {
  try {
    const url = new URL(urlStr);
    if (!['http:', 'https:'].includes(url.protocol)) return false;
    const hostname = url.hostname.toLowerCase();

    // Always block cloud metadata endpoints (SSRF escalation targets)
    const alwaysBlocked = ['metadata.google.internal', '169.254.169.254'];
    if (alwaysBlocked.includes(hostname)) return false;

    // If private networks are allowed (on-prem mode), permit everything else
    if (ALLOW_PRIVATE) return true;

    // Default-safe: also block loopback and private IP ranges
    const loopback = ['localhost', '127.0.0.1', '::1', '0.0.0.0'];
    if (loopback.includes(hostname)) return false;

    const parts = hostname.split('.').map(Number);
    if (parts.length === 4 && parts.every(p => !isNaN(p))) {
      if (parts[0] === 10) return false;
      if (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) return false;
      if (parts[0] === 192 && parts[1] === 168) return false;
    }
    return true;
  } catch {
    return false;
  }
}

const webhookUrlSchema = z.string().url().refine(isValidWebhookUrl, {
  message: 'Webhook URL is not allowed. Cloud metadata endpoints are blocked. Set WEBHOOK_ALLOW_PRIVATE=true for on-prem/LAN targets.',
});"}

