1	import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
2	
3	const ALGORITHM = 'aes-256-gcm';
4	const IV_LENGTH = 16;
5	const REQUIRED_KEY_LENGTH = 32;
6	
7	function getKey(): Buffer {
8	  const key = process.env.ENCRYPTION_KEY;
9	  if (!key) {
10	    throw new Error('ENCRYPTION_KEY environment variable is required');
11	  }
12	  const keyBuffer = Buffer.from(key, 'utf-8');
13	  if (keyBuffer.length !== REQUIRED_KEY_LENGTH) {
14	    throw new Error(
15	      `ENCRYPTION_KEY must be exactly ${REQUIRED_KEY_LENGTH} bytes (got ${keyBuffer.length}). ` +
16	      'Provide a 32-character UTF-8 string or a 32-byte key.'
17	    );
18	  }
19	  return keyBuffer;
20	}
21	
22	export function encrypt(plaintext: string): string {
23	  const key = getKey();
24	  const iv = randomBytes(IV_LENGTH);
25	  const cipher = createCipheriv(ALGORITHM, key, iv);
26	
27	  let encrypted = cipher.update(plaintext, 'utf-8', 'base64');
28	  encrypted += cipher.final('base64');
29	  const authTag = cipher.getAuthTag();
30	
31	  return `${iv.toString('base64')}:${authTag.toString('base64')}:${encrypted}`;
32	}
33	
34	export function decrypt(encryptedData: string): string {
35	  const key = getKey();
36	  const parts = encryptedData.split(':');
37	  if (parts.length !== 3) {
38	    throw new Error('Invalid encrypted data format');
39	  }
40	
41	  const iv = Buffer.from(parts[0], 'base64');
42	  const authTag = Buffer.from(parts[1], 'base64');
43	  const encrypted = parts[2];
44	
45	  const decipher = createDecipheriv(ALGORITHM, key, iv);
46	  decipher.setAuthTag(authTag);
47	
48	  let decrypted = decipher.update(encrypted, 'base64', 'utf-8');
49	  decrypted += decipher.final('utf-8');
50	
51	  return decrypted;
52	}
