2	import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
3	import { getKnex } from '../../infrastructure/database/connection.js';
4	import { logger } from '../../infrastructure/logging/index.js';
5	
6	export default fp(async (app: FastifyInstance) => {
7	  app.addHook('onResponse', async (request: FastifyRequest, reply: FastifyReply) => {
8	    const method = request.method.toUpperCase();
9	    if (!['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) return;
10	
11	    try {
12	      const db = getKnex();
13	
14	      // Audit writes run after the per-request transaction is committed,
15	      // so we use an independent transaction with RLS bypass to insert
16	      // into the audit_log table (which has super_admin-only RLS policy).
17	      await db.transaction(async (trx) => {
18	        await trx.raw("SET LOCAL app.bypass_rls = 'true'");
19	
20	        const userId = (request as any).user?.userId ?? null;
21	        const urlParts = request.url.split('/').filter(Boolean);
22	        const entityType = urlParts[1] ?? 'unknown';
23	        const entityId = urlParts[2] ?? null;
24	
25	        await trx('audit_log').insert({
26	          user_id: userId,
27	          action: `${method} ${request.url}`,
28	          entity_type: entityType,
29	          entity_id: entityId && entityId.match(/^[0-9a-f-]{36}$/) ? entityId : null,
30	          old_state: (request as any)._auditOldState ?? null,
31	          new_state: (request as any)._auditNewState ?? null,
32	          ip_address: request.ip,
33	        });
34	      });
35	    } catch (err) {
36	      logger.error({ err }, 'Failed to write audit log');
37	    }
38	  });
39	}, { name: 'audit' });
