23	export class KnexSessionRepository implements SessionRepository {
24	  constructor(private db: Knex) {}
25	
26	  async findByUserIdAndNonce(userId: string, nonce: string): Promise<Session | null> {
27	    const row = await this.db('user_sessions')
28	      .where({ user_id: userId, session_nonce: nonce })
29	      .where('expires_at', '>', new Date())
30	      .first();
31	    return row ? toDomain(row) : null;
32	  }
33	
34	  async findByUserId(userId: string): Promise<Session[]> {
35	    const rows = await this.db('user_sessions')
36	      .where({ user_id: userId })
37	      .orderBy('created_at', 'desc');
38	    return rows.map(toDomain);
39	  }
40	
41	  async create(input: Omit<Session, 'id' | 'createdAt'>): Promise<Session> {
42	    const [row] = await this.db('user_sessions').insert({
43	      user_id: input.userId,
44	      session_nonce: input.sessionNonce,
45	      token_jti: input.tokenJti,
46	      ip_address: input.ipAddress ? encrypt(input.ipAddress) : null,
47	      workstation_id: input.workstationId ? encrypt(input.workstationId) : null,
48	      expires_at: input.expiresAt,
49	    }).returning('*');
50	    return toDomain(row);
51	  }
